import { useState, useEffect, useRef } from "react";
import galleryData from "../data/GaleriaFotos.jsx";
import FlechaAbajo from "../icons/flecha-abajo.svg";

const COLUMNAS = 3;
const FILA_INICIAL = 1;
const FILAS_POR_CLICK = 2;

const IMAGENES_INICIALES = COLUMNAS * FILA_INICIAL;
const IMAGENES_POR_CLICK = COLUMNAS * FILAS_POR_CLICK;

const MasonryGrid = () => {

  const [cantidadVisible, setCantidadVisible] = useState(IMAGENES_INICIALES);
  const gridRef = useRef(null);

  const imagenesMostrar = galleryData.slice(0, cantidadVisible);
  const estaExpandido = cantidadVisible >= galleryData.length;

  const toggleMostrar = () => {

    if (estaExpandido) {
      setCantidadVisible(IMAGENES_INICIALES);

      window.scrollTo({
        top: gridRef.current.offsetTop - 200,
        behavior: "smooth"
      });

    } else {
      setCantidadVisible(prev =>
        Math.min(prev + IMAGENES_POR_CLICK, galleryData.length)
      );
    }
  };

  // Pinterest masonry calculation
  useEffect(() => {

    const grid = gridRef.current;
    if (!grid) return;

    const rowHeight = 10;
    const gap = 16;

    const resizeGridItems = () => {

      const items = grid.querySelectorAll(".masonry-item");

      items.forEach(item => {

        const img = item.querySelector("img");

        if (!img.complete) {
          img.onload = resizeGridItems;
          return;
        }

        const height = img.getBoundingClientRect().height;
        const span = Math.ceil((height + gap) / (rowHeight + gap));

        item.style.gridRowEnd = `span ${span}`;

      });

    };

    resizeGridItems();

    window.addEventListener("resize", resizeGridItems);

    return () => window.removeEventListener("resize", resizeGridItems);

  }, [cantidadVisible]);

  return (
    <div className="flex flex-col items-center">

      {/* GRID PINTEREST */}
      <div
        ref={gridRef}
        className="grid grid-cols-2 md:grid-cols-3 gap-4 auto-rows-[10px]"
      >
        {imagenesMostrar.map(img => (
          <div key={img.id} className="masonry-item">
            <img
              src={img.src}
              alt={img.alt}
              className="w-full rounded-xl shadow-md hover:scale-[1.02] transition"
            />
          </div>
        ))}
      </div>

      {/* BOTON */}
      {galleryData.length > IMAGENES_INICIALES && (
        <button
          onClick={toggleMostrar}
          className="mt-8 hover:scale-110 transition"
        >
          <img
            src={FlechaAbajo}
            className={`w-10 transition-transform duration-300 ${
              estaExpandido ? "rotate-180" : ""
            }`}
          />
        </button>
      )}

    </div>
  );

};

export default MasonryGrid;
